8	import { IJiraIdentityMappingBase } from '@modules/jira/types/jira-installation.interface';
9	
10	import { TABLE_NAME_JIRA_IDENTITY_MAPPINGS } from '@constants/db.constant';
11	
12	@Injectable()
13	export class JiraIdentityModel {
14		private readonly logger = new Logger(JiraIdentityModel.name);
15		private readonly tableName = TABLE_NAME_JIRA_IDENTITY_MAPPINGS;
16	
17		constructor(
18			@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
19			@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
20		) {}
21	
22		async upsert({
23			installationId,
24			jiraAccountId,
25			platformUserId,
26		}: {
27			installationId: string;
28			jiraAccountId: string;
29			platformUserId: string;
30		}): Promise<void> {
31			try {
32				await this.knexWrite<IJiraIdentityMappingBase>(this.tableName)
33					.insert({
34						_id: randomUUID(),
35						installation_id: installationId,
36						jira_account_id: jiraAccountId,
37						platform_user_id: platformUserId,
38						created_at: this.knexWrite.fn.now(),
39						updated_at: this.knexWrite.fn.now(),
40					})
41					.onConflict(['installation_id', 'jira_account_id'])
42					.merge(['platform_user_id', 'updated_at']);
43	
44				this.logger.debug(
45					`Upserted identity mapping: ${jiraAccountId} → ${platformUserId}`,
46				);
47			} catch (error) {
48				this.logger.error(
49					`Failed to upsert identity mapping for ${jiraAccountId}: ${(error as Error).message}`,
50				);
51				throw error;
52			}
53		}
54	
55		async findByInstallationAndAccountId({
56			installationId,
57			jiraAccountId,
58		}: {
59			installationId: string;
60			jiraAccountId: string;
61		}): Promise<IJiraIdentityMappingBase | null> {
62			try {
63				const result = await this.knexRead<IJiraIdentityMappingBase>(this.tableName)
64					.where({ installation_id: installationId, jira_account_id: jiraAccountId })
65					.first();
66				return result ?? null;
67			} catch (error) {
68				this.logger.error(
69					`Failed to find identity mapping for ${jiraAccountId}: ${(error as Error).message}`,
70				);
71				throw error;
72			}
73		}
74	}
