1	import { InjectQueue } from '@nestjs/bullmq';
2	import { Injectable, Logger, UnauthorizedException } from '@nestjs/common';
3	import { Queue } from 'bullmq';
4	
5	import { EnvConfigService } from '@modules/env-config/env-config.service';
6	import { IJiraWebhookIssuePayload } from '@modules/jira/types/jira-api.interface';
7	import { IProcessWebhookEventJob } from '@modules/jira/types/jira-sync.interface';
8	
9	import { JIRA_WEBHOOK_SECRET } from '@constants/env-variables.constant';
10	
11	const SUPPORTED_WEBHOOK_EVENTS = new Set(['jira:issue_created', 'jira:issue_updated']);
12	
13	@Injectable()
14	export class JiraWebhookService {
15		private readonly logger = new Logger(JiraWebhookService.name);
16	
17		constructor(
18			private readonly configService: EnvConfigService,
19			@InjectQueue('jira') private readonly jiraQueue: Queue,
20		) {}
21	
22		async handleEvent({
23			secret,
24			installationDbId,
25			payload,
26		}: {
27			secret: string;
28			installationDbId: string;
29			payload: IJiraWebhookIssuePayload;
30		}): Promise<void> {
31			const expectedSecret = this.configService.get<string>({ key: JIRA_WEBHOOK_SECRET });
32			if (secret !== expectedSecret) {
33				throw new UnauthorizedException('Invalid webhook secret');
34			}
35	
36			if (!SUPPORTED_WEBHOOK_EVENTS.has(payload.webhookEvent)) {
37				this.logger.debug(`Skipping unsupported webhook event: ${payload.webhookEvent}`);
38				return;
39			}
40	
41			await this.jiraQueue.add(
42				'process_webhook_event',
43				{ installationDbId, payload } satisfies IProcessWebhookEventJob,
44				{ attempts: 3, backoff: { type: 'exponential', delay: 5000 } },
45			);
46	
47			this.logger.debug(
48				`Queued process_webhook_event for installation ${installationDbId}, event ${payload.webhookEvent}`,
49			);
50		}
51	}
