5	@Injectable()
6	export class GithubIdentityService {
7		private readonly logger = new Logger(GithubIdentityService.name);
8	
9		constructor(private readonly contributorModel: GithubContributorModel) {}
10	
11		async claimGithubIdentity({
12			companyId,
13			platformUserId,
14			githubLogin,
15		}: {
16			companyId: string;
17			platformUserId: string;
18			githubLogin: string;
19		}): Promise<void> {
20			const contributors = await this.contributorModel.findByGithubLoginAcrossInstallations(
21				{
22					companyId,
23					githubLogin,
24				},
25			);
26	
27			if (contributors.length === 0) {
28				throw new NotFoundException(
29					`No GitHub contributor found with login "${githubLogin}" in your company`,
