31			}
32	
33			for (const contributor of contributors) {
34				await this.contributorModel.linkPlatformUser({
35					contributorId: contributor._id,
36					platformUserId,
37				});
38			}
39	
40			this.logger.debug(
41				`Linked ${String(contributors.length)} contributor records to platform user ${platformUserId}`,
