40					});
41					return;
42				}
43	
44				if (job.name === 'sync_project') {
45					const data = job.data as ISyncProjectJob;
46					await this.syncService.syncProject({
47						installationDbId: data.installationDbId,
48						projectDbId: data.projectDbId,
49						projectKey: data.projectKey,
50					});
51					return;
52				}
53	
54				if (job.name === 'process_webhook_event') {
55					const data = job.data as IProcessWebhookEventJob;
56					await this.syncService.processWebhookIssueEvent({
57						installationDbId: data.installationDbId,
58						payload: data.payload,
59					});
60					return;
61				}
62	
63				this.logger.warn(`Unknown job type: ${job.name}`);
64			} catch (error) {
65				this.logger.error(
66					`Job ${job.name} (${job.id}) failed: ${(error as Error).message}`,
67				);
68				throw error;
