3	import { Injectable, Logger } from '@nestjs/common';
4	import { Knex } from 'knex';
5	import { InjectConnection } from 'nest-knexjs';
6	
7	import { KNEX_READ_CONNECTION, KNEX_WRITE_CONNECTION } from '@modules/db/db.constant';
8	import {
9		IGithubContributorBase,
10		IGithubContributorUpsert,
11	} from '@modules/github/types/github-contributor.interface';
12	
13	import { TABLE_NAME_GITHUB_CONTRIBUTORS } from '@constants/db.constant';
14	
15	@Injectable()
16	export class GithubContributorModel {
17		private readonly logger = new Logger(GithubContributorModel.name);
18		private readonly tableName = TABLE_NAME_GITHUB_CONTRIBUTORS;
19	
20		constructor(
21			@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
22			@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
23		) {}
24	
25		async upsert({ data }: { data: IGithubContributorUpsert }): Promise<void> {
26			try {
27				await this.knexWrite<IGithubContributorBase>(this.tableName)
28					.insert({
29						_id: randomUUID(),
30						...data,
31						created_at: this.knexWrite.fn.now(),
32						updated_at: this.knexWrite.fn.now(),
33					})
34					.onConflict(['installation_id', 'github_user_id'])
35					.merge(['github_login', 'github_name', 'github_email', 'updated_at']);
36	
37				this.logger.debug(
38					`Upserted contributor ${data.github_login} for installation ${data.installation_id}`,
39				);
40			} catch (error) {
41				this.logger.error(
42					`Failed to upsert contributor ${data.github_login}: ${(error as Error).message}`,
43				);
44				throw error;
45			}
46		}
47	
48		async findByGithubLoginAcrossInstallations({
49			companyId,
50			githubLogin,
51		}: {
52			companyId: string;
53			githubLogin: string;
54		}): Promise<IGithubContributorBase[]> {
55			try {
56				return await this.knexRead<IGithubContributorBase>(this.tableName)
57					.join(
58						'github_installations',
59						'github_installations._id',
60						'=',
61						`${this.tableName}.installation_id`,
62					)
63					.where({
64						'github_installations.company_id': companyId,
65						[`${this.tableName}.github_login`]: githubLogin,
66					})
67					.select(`${this.tableName}.*`);
68			} catch (error) {
69				this.logger.error(
70					`Failed to find contributors by login ${githubLogin}: ${(error as Error).message}`,
71				);
72				throw error;
73			}
74		}
75	
76		async linkPlatformUser({
77			contributorId,
78			platformUserId,
79		}: {
80			contributorId: string;
81			platformUserId: string;
82		}): Promise<void> {
83			try {
84				await this.knexWrite<IGithubContributorBase>(this.tableName)
85					.where({ _id: contributorId })
86					.update({
87						platform_user_id: platformUserId,
88						updated_at: this.knexWrite.fn.now(),
89					});
90	
91				this.logger.debug(
92					`Linked contributor ${contributorId} to platform user ${platformUserId}`,
93				);
94			} catch (error) {
95				this.logger.error(
96					`Failed to link contributor ${contributorId}: ${(error as Error).message}`,
97				);
98				throw error;
99			}
100		}
101	
102		async findByInstallationAndLogin({
103			installationId,
104			githubLogin,
105		}: {
106			installationId: string;
107			githubLogin: string;
108		}): Promise<IGithubContributorBase | null> {
109			try {
110				const result = await this.knexRead<IGithubContributorBase>(this.tableName)
111					.where({ installation_id: installationId, github_login: githubLogin })
112					.first();
113	
114				return result ?? null;
115			} catch (error) {
116				this.logger.error(
117					`Failed to find contributor ${githubLogin} for installation ${installationId}: ${(error as Error).message}`,
118				);
119				throw error;
120			}
121		}
122	}
