import { Logger } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';

import { KNEX_READ_CONNECTION, KNEX_WRITE_CONNECTION } from '@modules/db/db.constant';
import { JiraIdentityModel } from '@modules/jira/db/jira-identity.model';
import { IJiraIdentityMappingBase } from '@modules/jira/types/jira-installation.interface';

const mockIdentityMapping: IJiraIdentityMappingBase = {
	_id: 'mapping-uuid-1',
	installation_id: 'install-uuid-1',
	jira_account_id: 'atlassian-account-1',
	platform_user_id: 'platform-user-1',
	created_at: new Date('2026-01-01'),
	updated_at: new Date('2026-01-01'),
};

const mockKnexRead = {
	where: jest.fn().mockReturnThis(),
	first: jest.fn(),
};

const mockKnexWrite = {
	insert: jest.fn().mockReturnThis(),
	onConflict: jest.fn().mockReturnThis(),
	merge: jest.fn(),
};

const knexReadFn = jest.fn().mockReturnValue(mockKnexRead);
const knexWriteFn = jest.fn().mockReturnValue(mockKnexWrite);

(knexWriteFn as jest.Mock & { fn: { now: jest.Mock } }).fn = {
	now: jest.fn().mockReturnValue('NOW()'),
};

describe('JiraIdentityModel', () => {
	let model: JiraIdentityModel;

	beforeEach(async () => {
		jest.clearAllMocks();

		knexReadFn.mockReturnValue(mockKnexRead);
		knexWriteFn.mockReturnValue(mockKnexWrite);
		mockKnexRead.where.mockReturnThis();
		mockKnexWrite.insert.mockReturnThis();
		mockKnexWrite.onConflict.mockReturnThis();

		const module: TestingModule = await Test.createTestingModule({
			providers: [
				JiraIdentityModel,
				{ provide: KNEX_READ_CONNECTION, useValue: knexReadFn },
				{ provide: KNEX_WRITE_CONNECTION, useValue: knexWriteFn },
			],
		}).compile();

		model = module.get<JiraIdentityModel>(JiraIdentityModel);

		jest.spyOn(Logger.prototype, 'log').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'error').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'debug').mockImplementation(jest.fn());
	});

	afterEach(() => jest.clearAllMocks());

	it('should be defined', () => {
		expect(model).toBeDefined();
	});

	describe('upsert', () => {
		it('should insert with onConflict merge', async () => {
			mockKnexWrite.merge = jest.fn().mockResolvedValue(undefined);

			await model.upsert({
				installationId: 'install-uuid-1',
				jiraAccountId: 'atlassian-account-1',
				platformUserId: 'platform-user-1',
			});

			expect(knexWriteFn).toHaveBeenCalled();
			expect(mockKnexWrite.insert).toHaveBeenCalledWith(
				expect.objectContaining({
					installation_id: 'install-uuid-1',
					jira_account_id: 'atlassian-account-1',
					platform_user_id: 'platform-user-1',
				}),
			);
			expect(mockKnexWrite.onConflict).toHaveBeenCalledWith([
				'installation_id',
				'jira_account_id',
			]);
			expect(mockKnexWrite.merge).toHaveBeenCalledWith(['platform_user_id', 'updated_at']);
		});

		it('should throw when DB throws', async () => {
			mockKnexWrite.merge = jest.fn().mockRejectedValue(new Error('DB write error'));

			await expect(
				model.upsert({
					installationId: 'install-uuid-1',
					jiraAccountId: 'atlassian-account-1',
					platformUserId: 'platform-user-1',
				}),
			).rejects.toThrow('DB write error');
		});
	});

	describe('findByInstallationAndAccountId', () => {
		it('should return the mapping when found', async () => {
			mockKnexRead.first = jest.fn().mockResolvedValue(mockIdentityMapping);

			const result = await model.findByInstallationAndAccountId({
				installationId: 'install-uuid-1',
				jiraAccountId: 'atlassian-account-1',
			});

			expect(knexReadFn).toHaveBeenCalled();
			expect(mockKnexRead.where).toHaveBeenCalledWith({
				installation_id: 'install-uuid-1',
				jira_account_id: 'atlassian-account-1',
			});
			expect(result).toEqual(mockIdentityMapping);
		});

		it('should return null when not found', async () => {
			mockKnexRead.first = jest.fn().mockResolvedValue(undefined);

			const result = await model.findByInstallationAndAccountId({
				installationId: 'install-uuid-1',
				jiraAccountId: 'nonexistent-account',
			});

			expect(result).toBeNull();
		});

		it('should throw when DB throws', async () => {
			mockKnexRead.first = jest.fn().mockRejectedValue(new Error('DB read error'));

			await expect(
				model.findByInstallationAndAccountId({
					installationId: 'install-uuid-1',
					jiraAccountId: 'atlassian-account-1',
				}),
			).rejects.toThrow('DB read error');
		});
	});
});

