import { JiraWebhookService } from '@modules/jira/jira-webhook.service';

import type { App } from 'supertest/types';

const mockWebhookService = {
	handleEvent: jest.fn(),
};

const validPayload = {
	webhookEvent: 'jira:issue_updated',
	timestamp: Date.now(),
	issue: {
		id: 'jira-issue-1',
		key: 'ENG-1',
		fields: {
			summary: 'Test issue',
			issuetype: { name: 'Bug' },
			status: { name: 'In Progress' },
			priority: { name: 'High' },
			assignee: { accountId: 'user-1' },
			reporter: { accountId: 'user-2' },
			customfield_10016: 3,
			resolutiondate: null,
			created: new Date().toISOString(),
			updated: new Date().toISOString(),
		},
	},
};

describe('JiraWebhookController (e2e)', () => {
	let app: NestFastifyApplication;
	let httpServer: App;

	beforeAll(async () => {
		const moduleFixture: TestingModule = await Test.createTestingModule({
			controllers: [JiraWebhookController],
			providers: [{ provide: JiraWebhookService, useValue: mockWebhookService }],
		}).compile();

		app = moduleFixture.createNestApplication<NestFastifyApplication>(new FastifyAdapter());
		await app.init();
		await app.getHttpAdapter().getInstance().ready();

		httpServer = app.getHttpServer() as App;
	});

	afterAll(async () => {
		await app.close();
	});

	beforeEach(() => jest.clearAllMocks());

	describe('POST /integrations/jira/webhook/:installationId', () => {
		it('should return 200 when service handles event successfully', async () => {
			mockWebhookService.handleEvent.mockResolvedValue(undefined);

			const res = await request(httpServer)
				.post('/integrations/jira/webhook/install-uuid-1')
				.query({ secret: 'test-jira-webhook-secret' })
				.send(validPayload);

			expect(res.status).toBe(HttpStatus.OK);
			expect(mockWebhookService.handleEvent).toHaveBeenCalledWith({
				secret: 'test-jira-webhook-secret',
				installationDbId: 'install-uuid-1',
				payload: expect.objectContaining({ webhookEvent: 'jira:issue_updated' }),
			});
		});

		it('should return 401 when service throws UnauthorizedException', async () => {
			const { UnauthorizedException } = await import('@nestjs/common');
			mockWebhookService.handleEvent.mockRejectedValue(
				new UnauthorizedException('Invalid webhook secret'),
			);

			const res = await request(httpServer)
				.post('/integrations/jira/webhook/install-uuid-1')
				.query({ secret: 'wrong-secret' })
				.send(validPayload);

			expect(res.status).toBe(HttpStatus.UNAUTHORIZED);
		});

		it('should return 200 with missing secret param (empty string forwarded to service)', async () => {
			mockWebhookService.handleEvent.mockResolvedValue(undefined);

			const res = await request(httpServer)
				.post('/integrations/jira/webhook/install-uuid-1')
				.send(validPayload);

			expect(res.status).toBe(HttpStatus.OK);
			expect(mockWebhookService.handleEvent).toHaveBeenCalledWith(
				expect.objectContaining({ secret: '' }),
			);
		});

		it('should return 200 for jira:issue_created event', async () => {
			mockWebhookService.handleEvent.mockResolvedValue(undefined);

			const createdPayload = { ...validPayload, webhookEvent: 'jira:issue_created' };

			const res = await request(httpServer)
				.post('/integrations/jira/webhook/install-uuid-2')
				.query({ secret: 'test-jira-webhook-secret' })
				.send(createdPayload);

			expect(res.status).toBe(HttpStatus.OK);
			expect(mockWebhookService.handleEvent).toHaveBeenCalledWith(
				expect.objectContaining({
					installationDbId: 'install-uuid-2',
				}),
			);
		});

		it('should return 500 when service throws unexpected error', async () => {
			mockWebhookService.handleEvent.mockRejectedValue(new Error('Unexpected failure'));

			const res = await request(httpServer)
				.post('/integrations/jira/webhook/install-uuid-1')
				.query({ secret: 'test-jira-webhook-secret' })
				.send(validPayload);

			expect(res.status).toBe(HttpStatus.INTERNAL_SERVER_ERROR);
		});
	});
});

